import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"基金定投","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/fund-regular-investment.md","filePath":"zh-CN/funds-and-wealth/fund-regular-investment.md"}'),l={name:"funds-and-wealth/fund-regular-investment.md"};function n(o,t,h,i,s,u){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="基金定投" tabindex="-1">基金定投 <a class="header-anchor" href="#基金定投" aria-label="Permalink to &quot;基金定投&quot;">​</a></h1><p>基金定投（定期定额投资）是指按照预设的时间周期和固定金额，自动买入指定基金的投资方式。通过分散买入时点，平摊持仓成本，降低择时带来的风险。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><p>财富页快捷入口「基金定投」，或「更多」→「基金定投」。</p><p>也可在基金订单页切换至「基金定投」标签，查看已有定投计划。</p><h2 id="设置定投计划" tabindex="-1">设置定投计划 <a class="header-anchor" href="#设置定投计划" aria-label="Permalink to &quot;设置定投计划&quot;">​</a></h2><h3 id="主要参数" tabindex="-1">主要参数 <a class="header-anchor" href="#主要参数" aria-label="Permalink to &quot;主要参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td>基金</td><td>选择参与定投的基金产品</td></tr><tr><td>定投金额</td><td>每期自动扣款并买入的固定金额</td></tr><tr><td>定投周期</td><td>扣款和买入的时间频率，如每周、每月</td></tr><tr><td>定投日</td><td>在所选周期内的具体日期</td></tr></tbody></table><h3 id="非交易日顺延与余额不足规则" tabindex="-1">非交易日顺延与余额不足规则 <a class="header-anchor" href="#非交易日顺延与余额不足规则" aria-label="Permalink to &quot;非交易日顺延与余额不足规则&quot;">​</a></h3><ul><li>定投日如遇非交易日，顺延至下一个交易日执行</li><li>每期买入按当期 T 日净值确认，与普通买入规则一致（截止时间 12:00 北京时间）</li><li>账户可用余额不足时，当期定投将跳过执行，不自动补扣</li></ul><h2 id="交易规则" tabindex="-1">交易规则 <a class="header-anchor" href="#交易规则" aria-label="Permalink to &quot;交易规则&quot;">​</a></h2><p>定投的每笔买入适用与普通基金相同的交易规则：</p><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 12:00 前触发</td><td>按 T 日净值确认买入</td></tr><tr><td>T+3 日</td><td>买入份额确认到账</td></tr><tr><td>T+4 日起</td><td>可查看持有收益</td></tr></tbody></table><p>详细交易规则参见<a href="./基金买入与卖出规则">基金买入与卖出规则</a>。</p><h2 id="查看与管理定投计划" tabindex="-1">查看与管理定投计划 <a class="header-anchor" href="#查看与管理定投计划" aria-label="Permalink to &quot;查看与管理定投计划&quot;">​</a></h2><p>在「基金订单」页切换至「基金定投」标签，可查看当前所有定投计划的状态、执行记录及累计持有情况。</p><p>可对定投计划执行以下操作：</p><ul><li><strong>暂停</strong>：停止后续自动扣款，已持有份额不受影响</li><li><strong>恢复</strong>：重新启用已暂停的定投计划</li><li><strong>终止</strong>：永久取消计划，不影响已购入份额的持有与赎回</li></ul><h2 id="费用" tabindex="-1">费用 <a class="header-anchor" href="#费用" aria-label="Permalink to &quot;费用&quot;">​</a></h2><p>定投买入适用基金的正常申购费率，无额外定投手续费。具体费率以基金详情页说明为准，详见<a href="./基金收费规则">基金收费规则</a>。</p><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><p>基金投资存在风险，定投不能保证盈利，也不能规避市场系统性风险。历史收益不代表未来表现，请根据自身风险承受能力谨慎决策。</p>',22)])])}const p=a(l,[["render",n]]);export{b as __pageData,p as default};
